SELECT COUNT(*) FROM reservations 
WHERE canteen_id = #{canteenId} 

    AND time_slot_id = #{timeSlotId}

AND reservation_status = 'RESERVED'

SELECT COUNT(*) FROM reservations 
WHERE canteen_id = #{canteenId} 

    AND time_slot_id = #{timeSlotId}

AND reservation_status = #{status}

SELECT DATE(r.created_at) as date, COUNT(CASE WHEN r.reservation_status = 'CHECKED_IN' THEN 1 END) as diningCount, COUNT(*) as reservationCount FROM reservations r JOIN canteen_time_slots s ON r.time_slot_id = s.id WHERE s.slot_date BETWEEN #{startDate} AND #{endDate}
AND r.canteen_id = #{canteenId}
GROUP BY DATE(r.created_at) ORDER BY date
